logger = logging.getLogger()
logger.setLevel(logging.INFO)

s3 = boto3.client("s3")
sns = boto3.client("sns")

OUTPUT_BUCKET = os.environ.get("OUTPUT_BUCKET")
SNS_TOPIC_ARN = os.environ.get("SNS_TOPIC_ARN")
OUTPUT_PREFIX = os.environ.get("OUTPUT_PREFIX", "processed/")
RESULT_SUFFIX = os.environ.get("RESULT_SUFFIX", ".json")


def lambda_handler(event, context):
    logger.info("Received event: %s", json.dumps(event))

    results = []
    errors = []

    for record in event.get("Records", []):
        try:
            if record.get("eventSource") != "aws:s3":
                logger.warning("Skipping non-S3 event record: %s", record)
                continue

            source_bucket = record["s3"]["bucket"]["name"]
            source_key = unquote_plus(record["s3"]["object"]["key"])

            result = process_s3_object(source_bucket, source_key)
            results.append(result)

            publish_notification(
                subject="Image Processing Succeeded",
                message={
                    "status": "success",
                    "source_bucket": source_bucket,
                    "source_key": source_key,
                    "output_bucket": result["output_bucket"],
                    "output_key": result["output_key"],
                    "processed_at": result["processed_at"],
                },
            )

        except Exception as e:
            error_info = {
                "error": str(e),
                "traceback": traceback.format_exc(),
                "record": record,
            }
            logger.error("Failed processing record: %s", json.dumps(error_info))
            errors.append(error_info)

            publish_notification(
                subject="Image Processing Failed",
                message=error_info,
            )

    response = {
        "processed_count": len(results),
        "error_count": len(errors),
        "results": results,
        "errors": errors,
    }

    logger.info("Lambda response: %s", json.dumps(response))
    return response


def process_s3_object(source_bucket, source_key):
    logger.info("Reading object from s3://%s/%s", source_bucket, source_key)

    obj = s3.get_object(Bucket=source_bucket, Key=source_key)
    body = obj["Body"].read()

    metadata = {
        "source_bucket": source_bucket,
        "source_key": source_key,
        "size_bytes": len(body),
        "processed_at": datetime.utcnow().isoformat() + "Z",
        "note": "MVP placeholder processing completed",
    }

    output_bucket = OUTPUT_BUCKET or source_bucket
    output_key = build_output_key(source_key)

    logger.info("Writing result to s3://%s/%s", output_bucket, output_key)

    s3.put_object(
        Bucket=output_bucket,
        Key=output_key,
        Body=json.dumps(metadata).encode("utf-8"),
        ContentType="application/json",
    )

    logger.info("Successfully processed s3://%s/%s", source_bucket, source_key)

    return {
        "source_bucket": source_bucket,
        "source_key": source_key,
        "output_bucket": output_bucket,
        "output_key": output_key,
        "processed_at": metadata["processed_at"],
    }


def build_output_key(source_key):
    filename = source_key.split("/")[-1]
    return f"{OUTPUT_PREFIX}{filename}{RESULT_SUFFIX}"


def publish_notification(subject, message):
    if not SNS_TOPIC_ARN:
        logger.warning("SNS_TOPIC_ARN not configured; skipping notification")
        return

    sns.publish(
        TopicArn=SNS_TOPIC_ARN,
        Subject=subject,
        Message=json.dumps(message, default=str),
    )